const result = $input.first().json;
const quotes = result.chart.result[0].indicators.quote[0];
const closes = quotes.close.filter(v => v !== null);
const highs = quotes.high.filter(v => v !== null);
const lows = quotes.low.filter(v => v !== null);

if (closes.length < 5) return [{ json: { signal: '', timeframe: '5min' } }];

const last = closes[closes.length - 1];
const pH = highs[highs.length - 2];
const pL = lows[lows.length - 2];
const pC = closes[closes.length - 2];

const PP = (pH + pL + pC) / 3;
const R1 = (2 * PP) - pL;
const R2 = PP + (pH - pL);
const S1 = (2 * PP) - pH;
const S2 = PP - (pH - pL);

function ema(data, p) {
  const k = 2 / (p + 1);
  let e = data[0];
  for (let i = 1; i < data.length; i++) e = data[i] * k + e * (1 - k);
  return e;
}
const e9 = ema(closes.slice(-20), 9);
const e20 = ema(closes.slice(-20), 20);

const sTop = Math.max(...highs.slice(-5));
const sBot = sTop - 40;
const dBot = Math.min(...lows.slice(-5));
const dTop = dBot + 40;

let signal = '';
let entry = 0, t1 = 0, t2 = 0, sl = 0, zone = '';

if (last <= S1 + 20 && last >= S1 - 20 && e9 > e20 && last >= dBot - 10 && last <= dTop + 20) {
  signal = 'BUY - CE Buy or PE Sell';
  entry = Math.round(last);
  sl = Math.round(S2 - 15);
  t1 = Math.round(PP);
  t2 = Math.round(R1);
  zone = 'DEMAND ZONE near S1';
}

if (last >= R1 - 20 && last <= R1 + 20 && e9 < e20 && last >= sBot - 20 && last <= sTop) {
  signal = 'SELL - PE Buy or CE Sell';
  entry = Math.round(last);
  sl = Math.round(R2 + 15);
  t1 = Math.round(PP);
  t2 = Math.round(S1);
  zone = 'SUPPLY ZONE near R1';
}

const IST = new Date().toLocaleTimeString('en-IN', { timeZone: 'Asia/Kolkata' });

return [{ json: { timeframe: '5min', signal, entry, target1: t1, target2: t2, stopLoss: sl, zone, PP: Math.round(PP), R1: Math.round(R1), R2: Math.round(R2), S1: Math.round(S1), S2: Math.round(S2), ema9: Math.round(e9), ema20: Math.round(e20), price: Math.round(last), time: IST } }];

